interface WalletRepository {
    fun getWallet(userId: String): Wallet?
    fun saveWallet(wallet: Wallet)
    fun updateBalance(userId: String, newBalance: BigDecimal): Wallet
}

interface TransactionRepository {
    fun save(record: TransactionRecord)
    fun findById(transactionId: String): TransactionRecord?
    fun updateStatus(transactionId: String, status: PaymentStatus): TransactionRecord?
}

class InMemoryWalletRepository : WalletRepository {
    private val wallets = ConcurrentHashMap<String, Wallet>()

    override fun getWallet(userId: String): Wallet? = wallets[userId]

    override fun saveWallet(wallet: Wallet) {
        wallets[wallet.userId] = wallet
    }

    override fun updateBalance(userId: String, newBalance: BigDecimal): Wallet {
        val existing = wallets[userId] ?: throw IllegalArgumentException("Wallet not found")
        val updated = existing.copy(balance = newBalance)
        wallets[userId] = updated
        return updated
    }
}

class InMemoryTransactionRepository : TransactionRepository {
    private val records = ConcurrentHashMap<String, TransactionRecord>()

    override fun save(record: TransactionRecord) {
        records[record.transactionId] = record
    }

    override fun findById(transactionId: String): TransactionRecord? = records[transactionId]

    override fun updateStatus(transactionId: String, status: PaymentStatus): TransactionRecord? {
        val existing = records[transactionId] ?: return null
        val updated = existing.copy(status = status)
        records[transactionId] = updated
        return updated
    }
}

