class SecureLogger {
    fun info(message: String) {
        android.util.Log.i("PaymentModule", sanitize(message))
    }

    fun warn(message: String) {
        android.util.Log.w("PaymentModule", sanitize(message))
    }

    fun error(message: String, throwable: Throwable? = null) {
        android.util.Log.e("PaymentModule", sanitize(message), throwable)
    }

    private fun sanitize(message: String): String {
        return message
            .replace(Regex("""\b\d{12,19}\b"""), "****")
            .replace(Regex("""(?i)(cvv|cvc|pin|token|secret)=\S+"""), "$1=****")
    }
}

class IntegrityUtil(private val secret: ByteArray) {
    fun hashTransaction(request: PaymentRequest): String {
        val payload = listOf(
            request.userId,
            request.amount.toPlainString(),
            request.currency,
            request.type.name,
            request.referenceId
        ).joinToString("|")
        val mac = Mac.getInstance("HmacSHA256")
        mac.init(SecretKeySpec(secret, "HmacSHA256"))
        return encode(mac.doFinal(payload.toByteArray(Charsets.UTF_8)))
    }

    fun sha256(value: String): String {
        val digest = MessageDigest.getInstance("SHA-256").digest(value.toByteArray(Charsets.UTF_8))
        return encode(digest)
    }

    private fun encode(bytes: ByteArray): String {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            Base64.getEncoder().encodeToString(bytes)
        } else {
            android.util.Base64.encodeToString(bytes, android.util.Base64.NO_WRAP)
        }
    }
}

