class PaymentValidator {
    fun validate(request: PaymentRequest) {
        require(request.userId.isNotBlank()) { "Invalid userId" }
        require(request.referenceId.isNotBlank()) { "Invalid referenceId" }
        require(request.currency.matches(Regex("^[A-Z]{3}$"))) { "Invalid currency" }
        require(request.amount > BigDecimal.ZERO) { "Amount must be positive" }
    }
}

class PaymentProcessor(
    private val context: Context,
    private val gateway: PaymentGateway,
    private val walletRepository: WalletRepository,
    private val transactionRepository: TransactionRepository,
    private val logger: SecureLogger = SecureLogger(),
    private val validator: PaymentValidator = PaymentValidator(),
    integritySecret: ByteArray = ByteArray(32).also { SecureRandom().nextBytes(it) }
) {
    private val cryptoManager = CryptoManager(context)
    private val integrityUtil = IntegrityUtil(integritySecret)

    @Synchronized
    fun process(request: PaymentRequest): PaymentResult {
        return try {
            validator.validate(request)
            when (request.type) {
                PaymentType.IN_APP_PURCHASE -> processInAppPurchase(request)
                PaymentType.WALLET_DEBIT -> processWalletDebit(request)
                PaymentType.WALLET_CREDIT -> processWalletCredit(request)
            }
        } catch (e: Exception) {
            logger.error("Payment processing failed for ref=${request.referenceId}", e)
            PaymentResult(
                transactionId = "",
                status = PaymentStatus.FAILED,
                message = e.message ?: "Unknown error"
            )
        }
    }

    fun encryptSensitiveData(raw: String): EncryptedPayload {
        return cryptoManager.encrypt(raw)
    }

    fun decryptSensitiveData(payload: EncryptedPayload): String {
        return cryptoManager.decrypt(payload)
    }

    private fun processInAppPurchase(request: PaymentRequest): PaymentResult {
        val auth = gateway.authorize(request)
        val record = createRecord(request, auth.transactionId, auth.status)
        transactionRepository.save(record)
        if (auth.status != PaymentStatus.AUTHORIZED) {
            return auth
        }
        val capture = gateway.capture(auth.transactionId)
        transactionRepository.updateStatus(auth.transactionId, capture.status)
        logger.info("In-app purchase processed tx=${capture.transactionId}")
        return capture
    }

    private fun processWalletDebit(request: PaymentRequest): PaymentResult {
        val wallet = walletRepository.getWallet(request.userId)
            ?: throw IllegalArgumentException("Wallet not found")
        require(wallet.currency == request.currency) { "Currency mismatch" }
        require(wallet.balance >= request.amount) { "Insufficient balance" }

        val newBalance = wallet.balance.subtract(request.amount)
        walletRepository.updateBalance(request.userId, newBalance)

        val txId = UUID.randomUUID().toString()
        val record = createRecord(request, txId, PaymentStatus.COMPLETED)
        transactionRepository.save(record)

        logger.info("Wallet debited tx=$txId user=${request.userId}")
        return PaymentResult(
            transactionId = txId,
            status = PaymentStatus.COMPLETED,
            message = "Wallet debited successfully"
        )
    }

    private fun processWalletCredit(request: PaymentRequest): PaymentResult {
        val wallet = walletRepository.getWallet(request.userId)
            ?: Wallet(request.userId, BigDecimal.ZERO, request.currency).also {
                walletRepository.saveWallet(it)
            }
        require(wallet.currency == request.currency) { "Currency mismatch" }

        val newBalance = wallet.balance.add(request.amount)
        walletRepository.updateBalance(request.userId, newBalance)

        val txId = UUID.randomUUID().toString()
        val record = createRecord(request, txId, PaymentStatus.COMPLETED)
        transactionRepository.save(record)

        logger.info("Wallet credited tx=$txId user=${request.userId}")
        return PaymentResult(
            transactionId = txId,
            status = PaymentStatus.COMPLETED,
            message = "Wallet credited successfully"
        )
    }

    private fun createRecord(
        request: PaymentRequest,
        transactionId: String,
        status: PaymentStatus
    ): TransactionRecord {
        return TransactionRecord(
            transactionId = transactionId,
            userId = request.userId,
            amount = request.amount,
            currency = request.currency,
            type = request.type,
            status = status,
            referenceId = request.referenceId,
            integrityHash = integrityUtil.hashTransaction(request),
            createdAt = System.currentTimeMillis()
        )
    }
}

